import psycopg2

DB_URL = "postgresql://postgres:postgres@db:5432/app_db"

descriptions_map = {
    "Чага": """<b>Березова Чага (Inonotus obliquus) — природний антиоксидант та детокс</b><br><br>Чага — це унікальний гриб, який вбирає в себе всю життєву силу берези. Це один із найпотужніших у світі джерел антиоксидантів, який допомагає організму боротися з наслідками поганої екології, стресу та неправильного харчування.<br><br><b>Головні переваги Чаги:</b><br>• <b>Глибоке очищення:</b> м'яко виводить токсини та підтримує роботу печінки.<br>• <b>Міцний імунітет:</b> стимулює природні захисні функції організму.<br>• <b>Енергія та молодість:</b> уповільнює процеси старіння на клітинному рівні завдяки високому вмісту меланіну та супероксиддисмутази (SOD).<br>• <b>Здорове травлення:</b> сприяє нормалізації роботи шлунково-кишкового тракту.<br><br><i>Ідеальна добавка для щоденного використання замість ранкової кави або чаю.</i><br><br><u><i>*Не є лікарським засобом. Перед використанням рекомендується консультація фахівця.</i></u>""",

    "Веселка": """<b>Гриб Веселка (Phallus impudicus) — традиційний еліксир життєвої сили</b><br><br>Веселка вважається одним із найзагадковіших та найцінніших грибів у народній традиції. Її багатий хімічний склад робить її універсальним помічником для підтримки загального здоров'я, швидкого відновлення та життєвого тонусу.<br><br><b>Для чого використовують Веселку:</b><br>• <b>Підтримка захисних сил:</b> активізує внутрішні ресурси організму в періоди сезонних навантажень.<br>• <b>Відновлення:</b> допомагає швидше повернутися до форми після фізичного та емоційного виснаження.<br>• <b>Чоловіче та жіноче здоров'я:</b> традиційно застосовується для підтримки гормонального балансу та репродуктивної системи.<br>• <b>Тонус судин:</b> сприяє підтримці нормального кровообігу.<br><br><i>Повністю натуральний продукт, зібраний в екологічно чистих умовах.</i><br><br><u><i>*Не є лікарським засобом. Продукт призначений для збагачення раціону харчування.</i></u>""",

    "Траметес": """<b>Траметес різнобарвний (Turkey Tail) — природний щит для вашого імунітету</b><br><br>Траметес, або "хвіст індички" — це гриб номер один у світі для комплексної підтримки імунної системи. Він містить унікальні полісахаридопептиди (PSK та PSP), які активно досліджуються сучасною наукою.<br><br><b>Користь Траметесу:</b><br>• <b>Активний імунітет:</b> допомагає організму розпізнавати та нейтралізувати зовнішні загрози.<br>• <b>Здорова мікрофлора:</b> діє як потужний пребіотик, створюючи ідеальне середовище для корисних бактерій у кишечнику.<br>• <b>Антиоксидантний захист:</b> багатий на феноли та флавоноїди, які захищають клітини від оксидативного стресу.<br><br><i>Ваш надійний захисник у будь-яку пору року.</i><br><br><u><i>*Не є лікарським засобом. Перед початком прийому рекомендується проконсультуватися з фахівцем.</i></u>""",

    "Лисичк": """<b>Лисичка справжня (Cantharellus cibarius) — делікатне очищення організму</b><br><br>Лисичка — це не тільки смачний лісовий делікатес, а й потужний інструмент для природного очищення організму. Завдяки вмісту хіноманнози, цей гриб створює несприятливі умови для непроханих "гостей" у нашому тілі, не завдаючи при цьому шкоди печінці та органам травлення.<br><br><b>Як працюють Лисички:</b><br>• <b>Антипаразитарна підтримка:</b> м'яке та безпечне очищення організму від токсинів та продуктів життєдіяльності шкідливих мікроорганізмів.<br>• <b>Підтримка печінки:</b> містить ергостерол та траметонолінову кислоту, які сприяють відновленню клітин печінки.<br>• <b>Зір та шкіра:</b> високий вміст вітаміну А та бета-каротину позитивно впливає на стан шкіри та слизових оболонок.<br><br><i>Безпечний природний детокс для всієї родини.</i><br><br><u><i>*Не є лікарським засобом. Продукт призначений для збагачення раціону харчування.</i></u>""",

    "CBD": """<b>CBD (Канабідіол) — природна гармонія та спокій без стресу</b><br><br>Преміальний екстракт CBD — це ваш особистий острівець спокою у бурхливому світі. Він взаємодіє з ендоканабіноїдною системою організму, допомагаючи повернути баланс нервовій системі без жодного психоактивного ефекту (0% THC).<br><br><b>Чому варто спробувати CBD:</b><br>• <b>Антистрес:</b> м'яко знімає відчуття тривожності, нервову напругу та метушливість думок.<br>• <b>Глибокий релакс:</b> допомагає розслабити тіло після тренувань або довгого робочого дня за комп'ютером.<br>• <b>Якісний сон:</b> полегшує процес засинання та робить сон безперервним, щоб зранку ви відчували себе на 100% зарядженими.<br>• <b>Фокус:</b> парадоксально, але зняття "фонового стресу" значно покращує концентрацію на робочих завданнях.<br><br><i>Абсолютно легальний, безпечний продукт, що не викликає звикання.</i><br><br><u><i>*Не є лікарським засобом. Перед використанням рекомендується консультація фахівця.</i></u>"""
}

def run_update():
    conn = None
    try:
        conn = psycopg2.connect(DB_URL)
        cur = conn.cursor()
        total_updated = 0
        for keyword, text in descriptions_map.items():
            cur.execute("UPDATE products SET description = %s WHERE name ILIKE %s", (text, f"%{keyword}%"))
            print(f"Оновлено товарів з '{keyword}': {cur.rowcount} шт.")
            total_updated += cur.rowcount
        conn.commit()
        cur.close()
        print(f"\n✅ БАТЧ 1 ЗАВЕРШЕНО! Загалом оновлено: {total_updated} позицій.")
    except Exception as e:
        print(f"Ошибка: {e}")
    finally:
        if conn: conn.close()

if __name__ == "__main__":
    run_update()
